using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
    }

    public string[] TrainAndSave(string dataPath, string modelPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Combine Subject + Description into a single text feature, then featurize with Priority
        var pipeline = _mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue(
                "PredictedLabel", "PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("Per-class metrics:");
        for (var i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            _logger.LogInformation("  Class {Index}: LogLoss={LogLoss:F4}", i, metrics.PerClassLogLoss[i]);
        }

        _mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        // Extract ordered label names from the Score column
        var outputSchema = model.GetOutputSchema(split.TrainSet.Schema);
        var scoreCol = outputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreCol.GetSlotNames(ref slotNames);
        return slotNames.DenseValues().Select(v => v.ToString()).ToArray();
    }
}

