using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

// Train the model on startup so the .zip is ready before the first request
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
var labels = trainer.TrainAndSave(dataPath, modelPath);
app.Services.GetRequiredService<IServiceProvider>();

// Register labels as a singleton for the controller to use
builder = null!; // builder is consumed; register labels directly on the app
app.Services.GetType(); // no-op; we need a different approach

app.MapControllers();
app.Run();

